import{c as i,S as a,j as h,m as t}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Soạn chương / chuyên đề / bài giảng","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/soan-bai-giang.md","filePath":"giao-vien/soan-bai-giang.md","lastUpdated":0}'),l={name:"giao-vien/soan-bai-giang.md"};function o(c,n,e,r,g,s){return a(),h("div",null,[...n[0]||(n[0]=[t(`<h1 id="soan-chuong-chuyen-đe-bai-giang" tabindex="-1">Soạn chương / chuyên đề / bài giảng <a class="header-anchor" href="#soan-chuong-chuyen-đe-bai-giang" aria-label="Permalink to “Soạn chương / chuyên đề / bài giảng”">​</a></h1><p>Đây là <strong>công đoạn quan trọng nhất</strong> của giáo viên - quyết định chất lượng khóa học.</p><h2 id="cau-truc-noi-dung" tabindex="-1">Cấu trúc nội dung <a class="header-anchor" href="#cau-truc-noi-dung" aria-label="Permalink to “Cấu trúc nội dung”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Khóa học</span></span>
<span class="line"><span>└── Chương (1, 2, 3...)</span></span>
<span class="line"><span>    └── Chuyên đề</span></span>
<span class="line"><span>        ├── Bài giảng (video, văn bản, file)</span></span>
<span class="line"><span>        └── Đề kiểm tra cuối chuyên đề</span></span></code></pre></div><h2 id="buoc-1-them-chuong" tabindex="-1">Bước 1 - Thêm chương <a class="header-anchor" href="#buoc-1-them-chuong" aria-label="Permalink to “Bước 1 - Thêm chương”">​</a></h2><ol><li>Vào chi tiết khóa → tab <strong>Cấu trúc nội dung</strong> (hoặc <code>https://lamsonedutech.vn/teacher/detail-course/:idCourse</code>).</li><li>Bấm <strong>Thêm chương</strong>.</li><li>Điền: <ul><li><strong>Tên chương</strong> (vd: &quot;Chương 1 - Hàm số&quot;)</li><li><strong>Số thứ tự</strong></li><li><strong>Mô tả ngắn</strong> (1-2 câu)</li><li>(Tùy chọn) <strong>Yêu cầu hoàn thành chương trước mới mở chương này</strong></li></ul></li><li>Lưu.</li></ol><h2 id="buoc-2-them-chuyen-đe" tabindex="-1">Bước 2 - Thêm chuyên đề <a class="header-anchor" href="#buoc-2-them-chuyen-đe" aria-label="Permalink to “Bước 2 - Thêm chuyên đề”">​</a></h2><ol><li>Bấm vào tên chương → mở chi tiết chương.</li><li>Bấm <strong>Thêm chuyên đề</strong> (<code>https://lamsonedutech.vn/teacher/detail-chapter/:idChapter</code>).</li><li>Điền: <ul><li><strong>Tên chuyên đề</strong> (vd: &quot;Bài 1.1 - Tập xác định&quot;)</li><li><strong>Số thứ tự</strong></li><li><strong>Mô tả</strong></li><li><strong>Mục tiêu học</strong> (sau bài này học viên sẽ làm được gì)</li></ul></li><li>Lưu.</li></ol><h2 id="buoc-3-them-bai-giang" tabindex="-1">Bước 3 - Thêm bài giảng <a class="header-anchor" href="#buoc-3-them-bai-giang" aria-label="Permalink to “Bước 3 - Thêm bài giảng”">​</a></h2><p>Trong chuyên đề (<code>https://lamsonedutech.vn/teacher/module-detail/:idThematic</code>), bấm <strong>Thêm bài giảng</strong>.</p><h3 id="loai-noi-dung-bai-giang" tabindex="-1">Loại nội dung bài giảng <a class="header-anchor" href="#loai-noi-dung-bai-giang" aria-label="Permalink to “Loại nội dung bài giảng”">​</a></h3><h4 id="a-video" tabindex="-1">a. Video <a class="header-anchor" href="#a-video" aria-label="Permalink to “a. Video”">​</a></h4><ul><li>Tải video lên (mp4 chuẩn H.264, ≤ 1-2GB tùy hệ thống).</li><li>Hoặc nhúng URL (YouTube unlisted, Vimeo, hệ thống lưu trữ riêng).</li><li>Thêm <strong>timestamp - chương phụ</strong> để học viên nhảy nhanh tới phần cần xem.</li></ul><h4 id="b-van-ban-rich-text" tabindex="-1">b. Văn bản (Rich text) <a class="header-anchor" href="#b-van-ban-rich-text" aria-label="Permalink to “b. Văn bản (Rich text)”">​</a></h4><ul><li>Soạn bằng trình soạn thảo có: <ul><li>Định dạng cơ bản (đậm, nghiêng, gạch chân)</li><li>Bullets, numbered list, bảng</li><li>Công thức toán LaTeX (vd: <code>$\\frac{a}{b}$</code>)</li><li>Chèn ảnh, video nhúng</li><li>Code block</li></ul></li></ul><h4 id="c-file-pdf-slide" tabindex="-1">c. File / PDF / Slide <a class="header-anchor" href="#c-file-pdf-slide" aria-label="Permalink to “c. File / PDF / Slide”">​</a></h4><ul><li>Upload file (PDF, DOCX, PPTX).</li><li>Chọn <strong>cho phép tải về</strong> hoặc <strong>chỉ đọc online</strong>.</li></ul><h4 id="d-mix" tabindex="-1">d. Mix <a class="header-anchor" href="#d-mix" aria-label="Permalink to “d. Mix”">​</a></h4><ul><li>Kết hợp: video chính + văn bản tóm tắt + file PDF kèm.</li></ul><h3 id="cau-hinh-them" tabindex="-1">Cấu hình thêm <a class="header-anchor" href="#cau-hinh-them" aria-label="Permalink to “Cấu hình thêm”">​</a></h3><ul><li><strong>Số phút ước lượng</strong> (hệ thống dùng để tính tổng thời lượng khóa).</li><li><strong>Yêu cầu xem hết video mới đánh dấu hoàn thành?</strong></li><li><strong>Cho phép comment dưới bài?</strong> (mặc định Có).</li></ul><h3 id="luu" tabindex="-1">Lưu <a class="header-anchor" href="#luu" aria-label="Permalink to “Lưu”">​</a></h3><ul><li>Bài giảng tự gắn vào chuyên đề hiện tại.</li><li>Có thể dùng lại bài giảng đã có trong <strong>Thư viện bài giảng</strong> thay vì upload mới.</li></ul><h2 id="buoc-4-đe-kiem-tra-cuoi-chuyen-đe" tabindex="-1">Bước 4 - Đề kiểm tra cuối chuyên đề <a class="header-anchor" href="#buoc-4-đe-kiem-tra-cuoi-chuyen-đe" aria-label="Permalink to “Bước 4 - Đề kiểm tra cuối chuyên đề”">​</a></h2><p>Trong chuyên đề, bấm <strong>Thêm đề kiểm tra</strong>.</p><h3 id="cach-1-chon-đe-co-san" tabindex="-1">Cách 1 - Chọn đề có sẵn <a class="header-anchor" href="#cach-1-chon-đe-co-san" aria-label="Permalink to “Cách 1 - Chọn đề có sẵn”">​</a></h3><ul><li>Mở danh sách đề từ <strong>kho đề</strong> của khóa.</li><li>Chọn 1 đề → cấu hình thời gian, số lần làm lại, hiển thị đáp án.</li></ul><h3 id="cach-2-tao-đe-moi-ngay" tabindex="-1">Cách 2 - Tạo đề mới ngay <a class="header-anchor" href="#cach-2-tao-đe-moi-ngay" aria-label="Permalink to “Cách 2 - Tạo đề mới ngay”">​</a></h3><ol><li>Chọn câu hỏi từ <strong>Danh mục câu hỏi</strong> (nếu bạn được Admin cấp quyền).</li><li>Hoặc dùng <strong>Tiêu chí đề thi</strong> để hệ thống random.</li><li>Sắp xếp thứ tự, đặt điểm cho từng câu.</li><li>Lưu.</li></ol><h3 id="cau-hinh-bai-kiem-tra" tabindex="-1">Cấu hình bài kiểm tra <a class="header-anchor" href="#cau-hinh-bai-kiem-tra" aria-label="Permalink to “Cấu hình bài kiểm tra”">​</a></h3><ul><li><strong>Thời gian làm bài</strong> (phút)</li><li><strong>Số câu</strong> / <strong>Điểm tối đa</strong></li><li><strong>Số lần làm lại</strong> (vd: 3 lần, hoặc Không giới hạn)</li><li><strong>Cho xem đáp án sau khi nộp?</strong></li><li><strong>Có xáo trộn câu hỏi / đáp án giữa các lần làm?</strong></li><li><strong>Điểm tối thiểu để mở chuyên đề kế</strong> (nếu khóa yêu cầu)</li></ul><h2 id="đe-on-khoa-hoc-toan-khoa" tabindex="-1">Đề ôn khóa học (toàn khóa) <a class="header-anchor" href="#đe-on-khoa-hoc-toan-khoa" aria-label="Permalink to “Đề ôn khóa học (toàn khóa)”">​</a></h2><p>Đề ôn khóa học = đề thi tổng kết, không gắn vào 1 chuyên đề cụ thể.</p><ol><li>Vào chi tiết khóa → tab <strong>Đề thi</strong>.</li><li>Bấm <strong>Thêm đề ôn</strong>.</li><li>Cấu hình tương tự đề kiểm tra chuyên đề.</li><li>Học viên sẽ thấy ở mục <strong>Đề ôn</strong> trong khóa của họ.</li></ol><h2 id="meo-soan-bai-giang-tot" tabindex="-1">Mẹo soạn bài giảng tốt <a class="header-anchor" href="#meo-soan-bai-giang-tot" aria-label="Permalink to “Mẹo soạn bài giảng tốt”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Video ngắn, mục tiêu rõ</p><ul><li>Mỗi video 7-12 phút, chỉ tập trung 1 mục tiêu nhỏ.</li><li>Mở đầu video nói rõ &quot;sau bài này em sẽ làm được X&quot;.</li><li>Kết thúc tóm tắt + đưa 1 câu hỏi để học viên kiểm tra hiểu.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Đa dạng định dạng</p><ul><li>Video chính → văn bản tóm tắt → 5 câu hỏi tự luyện → bài kiểm tra cuối chuyên đề.</li><li>Học viên có khẩu vị khác nhau.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Đặt mục tiêu mở khóa</p><ul><li>Bật <strong>yêu cầu xem hết video</strong> + <strong>điểm tối thiểu bài kiểm tra ≥ 5/10 mới mở chuyên đề kế</strong>.</li><li>Học viên sẽ học theo lộ trình thay vì nhảy cóc.</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi upload video bị lỗi giữa chừng.</strong> → Kiểm tra dung lượng, định dạng (mp4 H264), đường truyền. Nếu vẫn lỗi, nén bằng HandBrake xuống ~720p.</p><p><strong>Học viên báo &quot;không xem được video do nhà mạng chặn&quot;.</strong> → Có thể video lưu trữ trên server bị chặn. Liên hệ Admin/IT đổi sang CDN.</p><p><strong>Tôi muốn copy 1 chuyên đề sang khóa khác.</strong> → Vào chi tiết chuyên đề → <strong>... → Sao chép vào khóa khác</strong> (nếu hệ thống hỗ trợ).</p><p><strong>Học viên không thấy bài giảng mới?</strong> → Kiểm tra trạng thái bài (Nháp / Công khai). Yêu cầu họ reload (Ctrl+F5).</p>`,43)])])}const m=i(l,[["render",o]]);export{d as __pageData,m as default};
